-- Clubs module schema

-- Dance clubs / venues (first-class entities — location anchor + SEO surface)
CREATE TABLE clubs (
    id             uuid         PRIMARY KEY DEFAULT gen_random_uuid(),
    name           varchar(255) NOT NULL,
    slug           varchar(255) UNIQUE NOT NULL,
    description    text,
    country        varchar(100)   NOT NULL,
    city           varchar(100) NOT NULL,
    address        varchar(500),
    latitude       double precision NOT NULL,
    longitude      double precision NOT NULL,
    website        varchar(500),
    phone          varchar(50),
    is_verified    boolean      DEFAULT false,
    is_active      boolean      DEFAULT true,
    metadata       jsonb        DEFAULT '{}',
    -- TODO: replace owner_user_id with a dedicated Business entity in next gen
    owner_user_id  uuid         REFERENCES users(id) ON DELETE SET NULL,
    -- working_hours: {"mon":{"open":"09:00","close":"21:00"},...,"sun":null}
    working_hours  jsonb        DEFAULT NULL,
    created_at     timestamp    NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at     timestamp    NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX idx_clubs_coords       ON clubs(latitude, longitude);
CREATE INDEX idx_clubs_country_city ON clubs(country, city);
CREATE INDEX idx_clubs_slug         ON clubs(slug);
CREATE INDEX idx_clubs_active       ON clubs(is_active) WHERE is_active = true;
CREATE INDEX idx_clubs_verified     ON clubs(is_verified) WHERE is_verified = true;
CREATE INDEX idx_clubs_owner        ON clubs(owner_user_id) WHERE owner_user_id IS NOT NULL;

-- Club membership (many-to-many: user <-> club)
CREATE TABLE club_members (
    club_id   uuid        NOT NULL REFERENCES clubs(id) ON DELETE CASCADE,
    user_id   uuid        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    role      varchar(20) DEFAULT 'member',
    joined_at timestamp   NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (club_id, user_id)
);

CREATE INDEX idx_club_members_user ON club_members(user_id);
CREATE INDEX idx_club_members_club ON club_members(club_id);

-- Club ↔ Trainer relationship (many-to-many: trainer teaches at club)
CREATE TABLE club_trainers (
    club_id         uuid        NOT NULL REFERENCES clubs(id) ON DELETE CASCADE,
    trainer_user_id uuid        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    joined_at       timestamp   NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (club_id, trainer_user_id)
);

CREATE INDEX idx_club_trainers_club    ON club_trainers(club_id);
CREATE INDEX idx_club_trainers_trainer ON club_trainers(trainer_user_id);

-- Trainer ↔ Dancer relationship (many-to-many: trainer teaches dancer)
CREATE TABLE trainer_students (
    trainer_user_id uuid        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    dancer_user_id  uuid        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    enrolled_at     timestamp   NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (trainer_user_id, dancer_user_id)
);

CREATE INDEX idx_trainer_students_trainer ON trainer_students(trainer_user_id);
CREATE INDEX idx_trainer_students_dancer  ON trainer_students(dancer_user_id);


